import subprocess
salida = subprocess.run(['ipconfig'], capture_output=True, text=True).stdout
for linea in salida.splitlines():
    if 'IPv4' in linea or 'Máscara' in linea or 'puerta' in linea.lower():
        # la parte tras los ':' es el valor
        print(linea.split(':')[-1].strip())
